module gradient
  implicit none

contains
  function demsav(drdx,c,m,p,flag) result(grad)
    implicit none
    real*8,dimension(21,21)::drdx
    real*8,dimension(0:1331)::c
    real*8,dimension(0:16395)::m
    real*8,dimension(0:1331)::p
    real*8::grad
    integer::flag
    ! ::::::::::::::::::::
    real*8,dimension(0:1331)::dp

    call dbemsav(drdx,dp,m,p,flag)
    grad = dot_product(dp,c)

    return
  end function demsav

  subroutine dbemsav(drdx,dp,m,p,flag)
    implicit none
    real*8,dimension(21,21),intent(in)::drdx
    real*8,dimension(0:1331),intent(out)::dp
    real*8,dimension(0:16395),intent(in)::m
    real*8,dimension(0:1331),intent(in)::p
    integer::flag
    ! ::::::::::::::::::::
    real*8,dimension(0:16395)::dm

    call devmono(drdx,dm,m,flag)
    call devpoly(dm,p,dp)

    return
  end subroutine dbemsav

